using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut;

    public OrderServiceTests()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    // ── CreateOrder ─────────────────────────────────────────────

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 25.50m, 1));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(45.50m, order.Total); // 10*2 + 25.50*1
        Assert.AreSame(items, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsNonEmptyId()
    {
        var items = CreateItems(("Widget", 5.00m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 5.00m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}.");
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_CalculatesTotalCorrectly()
    {
        var items = CreateItems(("Widget", 7.25m, 4));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(29.00m, order.Total); // 7.25 * 4
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_GeneratesUniqueIds()
    {
        var items = CreateItems(("Widget", 1.00m, 1));

        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 1.00m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    // ── GetOrder ────────────────────────────────────────────────

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        var items = CreateItems(("Widget", 5.00m, 1));
        var created = _sut.CreateOrder("cust-1", items);

        var found = _sut.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
        Assert.AreEqual(created.Total, found.Total);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrder_AfterMultipleCreations_ReturnsCorrectOrder()
    {
        var order1 = _sut.CreateOrder("cust-1", CreateItems(("A", 1.00m, 1)));
        var order2 = _sut.CreateOrder("cust-2", CreateItems(("B", 2.00m, 1)));
        var order3 = _sut.CreateOrder("cust-3", CreateItems(("C", 3.00m, 1)));

        var found = _sut.GetOrder(order2.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual("cust-2", found.CustomerId);
    }

    // ── GetOrdersByCustomer ─────────────────────────────────────

    [TestMethod]
    public void GetOrdersByCustomer_WithOrders_ReturnsOnlyThatCustomersOrders()
    {
        _sut.CreateOrder("cust-1", CreateItems(("A", 1.00m, 1)));
        _sut.CreateOrder("cust-2", CreateItems(("B", 2.00m, 1)));
        _sut.CreateOrder("cust-1", CreateItems(("C", 3.00m, 1)));

        var orders = _sut.GetOrdersByCustomer("cust-1");

        Assert.AreEqual(2, orders.Count);
        Assert.IsTrue(orders.All(o => o.CustomerId == "cust-1"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var orders = _sut.GetOrdersByCustomer("unknown");

        Assert.AreEqual(0, orders.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_SingleOrder_ReturnsSingleElementList()
    {
        _sut.CreateOrder("cust-1", CreateItems(("Widget", 10.00m, 1)));

        var orders = _sut.GetOrdersByCustomer("cust-1");

        var single = Assert.ContainsSingle(orders);
        Assert.AreEqual("cust-1", single.CustomerId);
    }
}

